1132#VJ|    const matchingResultAfterSplit = messagesAfterSplit.some((message) => {
1133#MH|      if (!hasToolResults(message.message)) {
1134#QV|        return false;
1135#YP|      }
1136#HB|
1137#JS|      const resultIds = new Set(getToolResultIds(message.message));
1138#WM|      return toolCallIds.some((toolCallId) => resultIds.has(toolCallId));
